#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int* x = (int*)malloc(N * sizeof(int));
    int* y = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &x[i], &y[i]);
    }
    char* S = (char*)malloc((M + 1) * sizeof(char));
    scanf("%s", S);
    int currX = 0, currY = 0;
    for (int i = 0; i < M; i++) {
        if (S[i] == 'D') currY--;
        else if (S[i] == 'U') currY++;
        else if (S[i] == 'L') currX--;
        else if (S[i] == 'R') currX++;
        if (i > 0) {
            int sum = 0;
            for (int j = 0; j < N; j++) {
                sum += abs(currX - x[j]) + abs(currY - y[j]);
            }
            printf("%d\n", sum);
        }
    }
    free(x);
    free(y);
    free(S);
    return 0;
}

