import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int[] x = new int[N];
        int[] y = new int[N];
        for (int i = 0; i < N; i++) {
            x[i] = sc.nextInt();
            y[i] = sc.nextInt();
        }
        String S = sc.next();
        int currX = 0, currY = 0;
        for (int i = 0; i < M; i++) {
            if (S.charAt(i) == 'D') currY--;
            else if (S.charAt(i) == 'U') currY++;
            else if (S.charAt(i) == 'L') currX--;
            else if (S.charAt(i) == 'R') currX++;
            if (i > 0) {
                int sum = 0;
                for (int j = 0; j < N; j++) {
                    sum += Math.abs(currX - x[j]) + Math.abs(currY - y[j]);
                }
                System.out.println(sum);
            }
        }
    }
}

